<?php
declare(strict_types=1);namespace App\Repositories\ControlEscaneres\Pdo;use App\Repositories\ControlEscaneres\Contracts\ScannerInspectionRepositoryInterface;use App\DTO\ControlEscaneres\{ScannerInspectionCreateData,ScannerInspectionDetailData};use App\Domain\ControlEscaneres\{ScannerInspection,InspectionType,BatteryPercentage};
final class PdoScannerInspectionRepository extends AbstractPdoRepository implements ScannerInspectionRepositoryInterface{private function map(array$r):ScannerInspection{return new ScannerInspection((int)$r['id'],(int)$r['movimiento_id'],(int)$r['scanner_id'],new InspectionType($r['tipo']),$r['bateria_porcentaje']===null?null:new BatteryPercentage((int)$r['bateria_porcentaje']),$r['calificacion']===null?null:(int)$r['calificacion'],$r['observaciones'],$r['firma_usuario_evidencia_id']===null?null:(int)$r['firma_usuario_evidencia_id'],$r['firma_responsable_evidencia_id']===null?null:(int)$r['firma_responsable_evidencia_id'],$this->date($r['inspeccionada_at']),$r['registrada_por']===null?null:(int)$r['registrada_por'],$this->date($r['created_at']),$this->date($r['updated_at']));}private function many(string$q,array$p):array{return array_map(fn($r)=>$this->map($r),$this->stmt($q,$p)->fetchAll(\PDO::FETCH_ASSOC));}public function createInspection(ScannerInspectionCreateData$d):ScannerInspection{$this->stmt('INSERT INTO scanner_inspecciones(movimiento_id,scanner_id,tipo,bateria_porcentaje,calificacion,observaciones,firma_usuario_evidencia_id,firma_responsable_evidencia_id,inspeccionada_at,registrada_por)VALUES(:m,:s,:t,:b,:c,:o,:fu,:fr,:a,:u)',['m'=>$d->movementId,'s'=>$d->scannerId,'t'=>$d->type->value,'b'=>$d->battery?->value,'c'=>$d->rating,'o'=>$d->observations,'fu'=>$d->firmaUsuarioEvidenciaId,'fr'=>$d->firmaResponsableEvidenciaId,'a'=>$d->inspectedAt->format('Y-m-d H:i:s.u'),'u'=>$d->actor->userId]);$x=$this->findByMovementAndType($d->movementId,$d->type);foreach($d->details as$detail)$this->addDetail($x->id,$detail);return$x;}public function addDetail(int$id,ScannerInspectionDetailData$d):void{$this->stmt('INSERT INTO scanner_inspeccion_detalles(inspeccion_id,componente,estado,valor_numerico,valor_texto)VALUES(:i,:c,:e,:n,:t)',['i'=>$id,'c'=>$d->component,'e'=>$d->status,'n'=>$d->numericValue,'t'=>$d->textValue]);}public function findByMovementAndType(int$id,InspectionType$t):?ScannerInspection{$r=$this->stmt('SELECT * FROM scanner_inspecciones WHERE movimiento_id=:i AND tipo=:t',['i'=>$id,'t'=>$t->value])->fetch(\PDO::FETCH_ASSOC);return is_array($r)?$this->map($r):null;}public function listByScannerId(int$id):array{return$this->many('SELECT * FROM scanner_inspecciones WHERE scanner_id=:i',['i'=>$id]);}public function listByMovementId(int$id):array{return$this->many('SELECT * FROM scanner_inspecciones WHERE movimiento_id=:i',['i'=>$id]);}public function listDetailsByInspectionId(int$id):array{return$this->stmt('SELECT componente,estado,valor_numerico,valor_texto,observaciones FROM scanner_inspeccion_detalles WHERE inspeccion_id=:i',['i'=>$id])->fetchAll(\PDO::FETCH_ASSOC);}}
